SELECT MAX(annual) AS max_annual_rainfall
FROM rainfall_data
WHERE year = 2023;

SELECT annual
FROM rainfall_data
WHERE year = 2022 AND state_id = 0;

SELECT state_ut_name AS state_name
FROM states
ORDER BY state_ut_name;

SELECT annual AS total_annual_rainfall
FROM rainfall_data
WHERE district_id = 1 AND year = 2022;
